@Experimental
final class AdaptiveFilterSession {
	static final int NO_PENDING_DEPTH = -1;
	static final long INITIAL_INTERVAL = 1_024L;
	static final long MAX_INTERVAL = 65_536L;
	static final long MIN_TRIAL_PREFIXES = 128L;
	static final long MIN_ABSOLUTE_CHANGE = 2_048L;
	static final long HARD_PREFIX_WORK = 16_384L;

	final NativeBooleanFilter target;
	final AdaptiveFilterMetadata metadata;
	final FilterPlacementEnvelope envelope;
	final TupleExpr telemetryExpr;
	final long[] arrivalsByCandidate;
	final long[] evaluationsByCandidate;
	final long[] passedByCandidate;
	final long[] filteredByCandidate;
	final long[] blacklistUntil;
	final long[] windowArrivals;
	final long[] windowEvaluations;
	final long[] windowPassed;
	final long[] windowFiltered;
	PlacementState placement;
	int pendingDepth = NO_PENDING_DEPTH;
	long completedPrefixes;
	long filterWork;
	long rightOpens;
	long joinRows;
	long replayedRows;
	long materializedRows;
	long regionalWork;
	long interval = INITIAL_INTERVAL;
	long windowStartPrefix;
	long windowStartRegionalWork;
	long windowStartFilterWork;
	long lastCompletedWork;
	long moves;
	long commits;
	long rollbacks;
	long cooldowns;
	long windows;
	long cooldownUntil;
	boolean trial;
	int provenDepth;
	int trialCandidate = -1;
	double baselineNormalizedWork;
	boolean closed;

	AdaptiveFilterSession(NativeBooleanFilter target, AdaptiveFilterMetadata metadata,
			FilterPlacementEnvelope envelope) {
		this(target, metadata, envelope, null);
	}

	AdaptiveFilterSession(NativeBooleanFilter target, AdaptiveFilterMetadata metadata,
			FilterPlacementEnvelope envelope, TupleExpr telemetryExpr) {
		this.target = target;
		this.metadata = metadata;
		this.envelope = envelope;
		this.telemetryExpr = telemetryExpr;
		this.arrivalsByCandidate = new long[envelope.candidateDepths.length];
		this.evaluationsByCandidate = new long[envelope.candidateDepths.length];
		this.passedByCandidate = new long[envelope.candidateDepths.length];
		this.filteredByCandidate = new long[envelope.candidateDepths.length];
		this.blacklistUntil = new long[envelope.candidateDepths.length];
		this.windowArrivals = new long[envelope.candidateDepths.length];
		this.windowEvaluations = new long[envelope.candidateDepths.length];
		this.windowPassed = new long[envelope.candidateDepths.length];
		this.windowFiltered = new long[envelope.candidateDepths.length];
		this.placement = new PlacementState(0L, envelope.deepestLegalDepth);
		this.provenDepth = envelope.deepestLegalDepth;
	}

	void requestMove(int depth) {
		if (candidateIndex(depth) < 0) {
			throw new IllegalArgumentException("depth is outside the placement envelope: " + depth);
		}
		if (pendingDepth == NO_PENDING_DEPTH) {
			pendingDepth = depth;
		}
	}

	void prefixCompleted() {
		completedPrefixes++;
		long totalWork = totalWork();
		long prefixWork = totalWork - lastCompletedWork;
		lastCompletedWork = totalWork;
		if (pendingDepth != NO_PENDING_DEPTH) {
			int nextDepth = pendingDepth;
			pendingDepth = NO_PENDING_DEPTH;
			installMove(nextDepth, currentNormalizedWork());
			return;
		}
		if (prefixWork > HARD_PREFIX_WORK) {
			if (trial) {
				rollbackTrial();
			} else if (placement.activeDepth() != envelope.earliestLegalDepth) {
				installMove(envelope.earliestLegalDepth, currentNormalizedWork());
			}
			return;
		}

		long windowPrefixes = completedPrefixes - windowStartPrefix;
		if (trial) {
			long trialWork = windowWork();
			double expected = baselineNormalizedWork * windowPrefixes;
			double excess = trialWork - expected;
			if (windowPrefixes >= MIN_TRIAL_PREFIXES && trialWork > expected * 1.25d
					&& excess > MIN_ABSOLUTE_CHANGE) {
				rollbackTrial();
			} else if (windowPrefixes >= interval) {
				double saved = expected - trialWork;
				if (expected > 0.0d && saved >= MIN_ABSOLUTE_CHANGE && saved >= expected * 0.15d) {
					commitTrial();
				} else {
					rollbackTrial();
				}
			}
			return;
		}

		if (windowPrefixes < interval) {
			return;
		}
		windows++;
		if (windowStartPrefix < cooldownUntil) {
			resetWindow();
			return;
		}
		int nextDepth = proposeMove();
		if (nextDepth >= 0) {
			installMove(nextDepth, currentNormalizedWork());
		} else {
			resetWindow();
		}
	}

	private void installMove(int nextDepth, double baseline) {
		PlacementState current = placement;
		if (current.activeDepth() == nextDepth) {
			resetWindow();
			return;
		}
		provenDepth = current.activeDepth();
		trialCandidate = candidateIndex(nextDepth);
		baselineNormalizedWork = Math.max(0.0d, baseline);
		placement = new PlacementState(current.generation() + 1L, nextDepth);
		moves++;
		trial = true;
		interval = Math.min(MAX_INTERVAL, interval * 2L);
		resetWindow();
	}

	private void commitTrial() {
		trial = false;
		trialCandidate = -1;
		commits++;
		cooldowns++;
		cooldownUntil = completedPrefixes + interval;
		resetWindow();
	}

	private void rollbackTrial() {
		int rejectedCandidate = trialCandidate;
		if (rejectedCandidate >= 0) {
			blacklistUntil[rejectedCandidate] = Math.max(blacklistUntil[rejectedCandidate],
					completedPrefixes + 4L * interval);
		}
		PlacementState current = placement;
		placement = new PlacementState(current.generation() + 1L, provenDepth);
		trial = false;
		trialCandidate = -1;
		rollbacks++;
		interval = Math.min(MAX_INTERVAL, interval * 2L);
		cooldowns++;
		cooldownUntil = completedPrefixes + interval;
		resetWindow();
	}

	private int proposeMove() {
		int active = candidateIndex(placement.activeDepth());
		long evaluations = delta(evaluationsByCandidate, windowEvaluations, active);
		if (evaluations <= 0L) {
			return -1;
		}
		long passed = delta(passedByCandidate, windowPassed, active);
		long filtered = delta(filteredByCandidate, windowFiltered, active);
		double passRate = passed / (double) Math.max(1L, passed + filtered);
		double rejectRate = 1.0d - passRate;
		long regional = regionalWork - windowStartRegionalWork;
		long filter = filterWork - windowStartFilterWork;
		long work = Math.max(1L, regional + filter);
		double bestSaving = 0.0d;
		int best = -1;

		if (active > 0 && (rejectRate >= 0.20d || filter >= work * 0.25d)) {
			long activeArrivals = delta(arrivalsByCandidate, windowArrivals, active);
			double regionalPerArrival = regional / (double) Math.max(1L, activeArrivals);
			for (int candidate = 0; candidate < active; candidate++) {
				if (blacklistUntil[candidate] > completedPrefixes) {
					continue;
				}
				long candidateArrivals = delta(arrivalsByCandidate, windowArrivals, candidate);
				double avoided = Math.max(0.0d, activeArrivals - candidateArrivals * passRate);
				double extraEvaluations = Math.max(0L, candidateArrivals - evaluations);
				double saving = avoided * regionalPerArrival
						- extraEvaluations * metadata.estimatedCostUnits;
				if (saving > bestSaving) {
					bestSaving = saving;
					best = candidate;
				}
			}
		}

		if (passRate >= 0.90d) {
			long activeArrivals = delta(arrivalsByCandidate, windowArrivals, active);
			for (int candidate = active + 1; candidate < envelope.candidateDepths.length; candidate++) {
				if (blacklistUntil[candidate] > completedPrefixes) {
					continue;
				}
				long candidateArrivals = delta(arrivalsByCandidate, windowArrivals, candidate);
				if (candidateArrivals * 2L > activeArrivals) {
					continue;
				}
				double saving = (evaluations - candidateArrivals) * (double) metadata.estimatedCostUnits;
				if (saving > bestSaving) {
					bestSaving = saving;
					best = candidate;
				}
			}
		}
		return best < 0 ? -1 : envelope.candidateDepths[best];
	}

	private static long delta(long[] current, long[] previous, int index) {
		return current[index] - previous[index];
	}

	private double currentNormalizedWork() {
		long prefixes = completedPrefixes - windowStartPrefix;
		return prefixes <= 0L ? 0.0d : windowWork() / (double) prefixes;
	}

	private long windowWork() {
		return regionalWork - windowStartRegionalWork + filterWork - windowStartFilterWork;
	}

	private long totalWork() {
		return regionalWork + filterWork;
	}

	private void resetWindow() {
		windowStartPrefix = completedPrefixes;
		windowStartRegionalWork = regionalWork;
		windowStartFilterWork = filterWork;
		System.arraycopy(arrivalsByCandidate, 0, windowArrivals, 0, arrivalsByCandidate.length);
		System.arraycopy(evaluationsByCandidate, 0, windowEvaluations, 0, evaluationsByCandidate.length);
		System.arraycopy(passedByCandidate, 0, windowPassed, 0, passedByCandidate.length);
		System.arraycopy(filteredByCandidate, 0, windowFiltered, 0, filteredByCandidate.length);
	}

	boolean arrive(int depth, RowState row) {
		int candidate = candidateIndex(depth);
		arrivalsByCandidate[candidate]++;
		if (placement.activeDepth() != depth) {
			return true;
		}
		evaluationsByCandidate[candidate]++;
		filterWork += metadata.estimatedCostUnits;
		boolean accepted = target.accept(row);
		if (accepted) {
			passedByCandidate[candidate]++;
		} else {
			filteredByCandidate[candidate]++;
		}
		return accepted;
	}

	int candidateIndex(int depth) {
		for (int i = 0; i < envelope.candidateDepths.length; i++) {
			if (envelope.candidateDepths[i] == depth) {
				return i;
			}
		}
		return -1;
	}

	void rightOpened() {
		rightOpens++;
		recordRegionalWork(8L);
	}

	void joinRow() {
		joinRows++;
		recordRegionalWork(1L);
	}

	void replayedRow() {
		replayedRows++;
		recordRegionalWork(1L);
	}

	void materializedRow() {
		materializedRows++;
		recordRegionalWork(1L);
	}

	void recordRegionalWork(long work) {
		regionalWork += Math.max(0L, work);
	}

	void close() {
		if (!closed) {
			closed = true;
			target.close();
		}
	}

	void publishTelemetry() {
		if (telemetryExpr == null || !telemetryExpr.isRuntimeTelemetryEnabled()) {
			return;
		}
		long evaluations = sum(evaluationsByCandidate);
		long passed = sum(passedByCandidate);
		long filtered = sum(filteredByCandidate);
		LmdbNativeExplain.setRuntimeMetric(telemetryExpr, "adaptiveFilterPlacementEligible", 1L);
		LmdbNativeExplain.setRuntimeMetric(telemetryExpr, "adaptiveFilterPlacementAdmitted", 1L);
		LmdbNativeExplain.setRuntimeMetric(telemetryExpr, "adaptiveFilterPlacementReason", "ADMITTED");
		LmdbNativeExplain.setRuntimeMetric(telemetryExpr, "adaptiveFilterPlacementTargetId", metadata.filterId);
		LmdbNativeExplain.setRuntimeMetric(telemetryExpr, "adaptiveFilterPlacementCostUnits",
				metadata.estimatedCostUnits);
		LmdbNativeExplain.setRuntimeMetric(telemetryExpr, "adaptiveFilterPlacementInitialDepth",
				envelope.deepestLegalDepth);
		LmdbNativeExplain.setRuntimeMetric(telemetryExpr, "adaptiveFilterPlacementFinalDepth",
				placement.activeDepth());
		LmdbNativeExplain.setRuntimeMetric(telemetryExpr, "adaptiveFilterPlacementGeneration",
				placement.generation());
		LmdbNativeExplain.setRuntimeMetric(telemetryExpr, "adaptiveFilterPlacementInterval", interval);
		LmdbNativeExplain.setRuntimeMetric(telemetryExpr, "adaptiveFilterPlacementPrefixes", completedPrefixes);
		LmdbNativeExplain.setRuntimeMetric(telemetryExpr, "adaptiveFilterPlacementWindows", windows);
		LmdbNativeExplain.setRuntimeMetric(telemetryExpr, "adaptiveFilterPlacementEvaluations", evaluations);
		LmdbNativeExplain.setRuntimeMetric(telemetryExpr, "adaptiveFilterPlacementPassed", passed);
		LmdbNativeExplain.setRuntimeMetric(telemetryExpr, "adaptiveFilterPlacementFiltered", filtered);
		LmdbNativeExplain.setRuntimeMetric(telemetryExpr, "adaptiveFilterPlacementMoves", moves);
		LmdbNativeExplain.setRuntimeMetric(telemetryExpr, "adaptiveFilterPlacementCommits", commits);
		LmdbNativeExplain.setRuntimeMetric(telemetryExpr, "adaptiveFilterPlacementRollbacks", rollbacks);
		LmdbNativeExplain.setRuntimeMetric(telemetryExpr, "adaptiveFilterPlacementCooldowns", cooldowns);
		LmdbNativeExplain.setRuntimeMetric(telemetryExpr, "adaptiveFilterPlacementFilterWork", filterWork);
		LmdbNativeExplain.setRuntimeMetric(telemetryExpr, "adaptiveFilterPlacementRegionalWork", regionalWork);
		LmdbNativeExplain.setRuntimeMetric(telemetryExpr, "adaptiveFilterPlacementRightOpens", rightOpens);
		LmdbNativeExplain.setRuntimeMetric(telemetryExpr, "adaptiveFilterPlacementJoinRows", joinRows);
		LmdbNativeExplain.setRuntimeMetric(telemetryExpr, "adaptiveFilterPlacementReplayedRows", replayedRows);
		LmdbNativeExplain.setRuntimeMetric(telemetryExpr, "adaptiveFilterPlacementMaterializedRows",
				materializedRows);
		LmdbNativeExplain.setRuntimeMetric(telemetryExpr, "adaptiveFilterPlacementCandidateDepths",
				Arrays.toString(envelope.candidateDepths));
		LmdbNativeExplain.setRuntimeMetric(telemetryExpr, "adaptiveFilterPlacementCandidateArrivals",
				Arrays.toString(arrivalsByCandidate));
		LmdbNativeExplain.setRuntimeMetric(telemetryExpr, "adaptiveFilterPlacementCandidateEvaluations",
				Arrays.toString(evaluationsByCandidate));
		LmdbNativeExplain.setRuntimeMetric(telemetryExpr, "adaptiveFilterPlacementCandidateBlacklistUntil",
				Arrays.toString(blacklistUntil));
	}

	private static long sum(long[] values) {
		long sum = 0L;
		for (long value : values) {
			sum += value;
		}
		return sum;
	}
}

/** A non-owning gate; the adaptive owner closes the target filter through its lease. */
@Experimental
final class AdaptiveFilterGateCursor implements RowCursor {
	final RowCursor arg;
	final RowState row;
	final AdaptiveFilterSession session;
	final int depth;

	AdaptiveFilterGateCursor(RowCursor arg, RowState row, AdaptiveFilterSession session, int depth) {
		this.arg = arg;
		this.row = row;
		this.session = session;
		this.depth = depth;
	}

	@Override
	public boolean next() throws java.io.IOException {
		while (arg.next()) {
			if (session.arrive(depth, row)) {
				return true;
			}
		}
		return false;
	}

	@Override
	public void close() {
		arg.close();
	}
}

/** Applies pending placement changes only after the previously returned prefix has fully drained. */
@Experimental
final class AdaptivePrefixBoundaryCursor implements RowCursor {
	final RowCursor arg;
	final AdaptiveFilterSession session;
	boolean activePrefix;

	AdaptivePrefixBoundaryCursor(RowCursor arg, AdaptiveFilterSession session) {
		this.arg = arg;
		this.session = session;
	}

	@Override
	public boolean next() throws java.io.IOException {
		if (activePrefix) {
			session.prefixCompleted();
		}
		activePrefix = arg.next();
		return activePrefix;
	}

	@Override
	public void close() {
		arg.close();
	}
}

/** Instrumented counterpart to {@link JoinCursor}; ordinary nested-loop execution never enters this class. */
@Experimental
final class AdaptiveJoinCursor implements RowCursor {
	static final int MAX_MATERIALIZED_ROWS = JoinCursor.MAX_MATERIALIZED_ROWS;

	final RowCursor leftCursor;
	final SlotPlan right;
	final RowState row;
	final AdaptiveFilterSession session;
	final int depth;
	final int[] replaySlots;
	RowCursor rightCursor;
	NativeLmdbQuerySource.NativeProbe rightProbe;
	ArrayList<long[]> materialized;
	boolean rightMaterialized;
	int replayIndex = -1;
	int replayMark = -1;

	AdaptiveJoinCursor(RowCursor leftCursor, SlotPlan right, RowState row, long leftProducedMask,
			AdaptiveFilterSession session, int depth) {
		this.leftCursor = leftCursor;
		this.right = right;
		this.row = row;
		this.session = session;
		this.depth = depth;
		long readMask = memoReadMask(right);
		this.replaySlots = readMask >= 0L && (readMask & leftProducedMask) == 0L
				? slotsOf(right.producedMask())
				: null;
	}

	@Override
	public boolean next() throws IOException {
		if (rightMaterialized) {
			return replayNext();
		}
		while (true) {
			if (rightCursor != null) {
				if (rightCursor.next()) {
					session.joinRow();
					if (materialized != null) {
						record();
					}
					return true;
				}
				closeRight();
				if (materialized != null) {
					rightMaterialized = true;
					replayIndex = -1;
					return replayNext();
				}
			}
			if (!leftCursor.next()) {
				return false;
			}
			rightCursor = openRight();
			session.rightOpened();
			if (replaySlots != null && materialized == null && !rightMaterialized) {
				materialized = new ArrayList<>();
			}
		}
	}

	RowCursor openRight() throws IOException {
		if (right instanceof PatternPlan pattern) {
			if (rightProbe == null) {
				rightProbe = row.source.newProbe();
			}
			return pattern.open(row, rightProbe);
		}
		return right.open(row);
	}

	boolean replayNext() throws IOException {
		while (true) {
			if (replayIndex >= 0) {
				releaseReplay();
				while (replayIndex < materialized.size()) {
					long[] values = materialized.get(replayIndex++);
					int mark = row.mark();
					if (bindReplay(values)) {
						replayMark = mark;
						session.replayedRow();
						return true;
					}
					row.rollback(mark);
				}
				replayIndex = -1;
			}
			if (!leftCursor.next()) {
				return false;
			}
			replayIndex = 0;
		}
	}

	boolean bindReplay(long[] values) {
		for (int i = 0; i < replaySlots.length; i++) {
			long value = values[i];
			if (value != UNKNOWN && !row.bind(replaySlots[i], value)) {
				return false;
			}
		}
		return true;
	}

	void record() {
		if (materialized.size() >= MAX_MATERIALIZED_ROWS) {
			materialized = null;
			return;
		}
		long[] values = new long[replaySlots.length];
		for (int i = 0; i < replaySlots.length; i++) {
			values[i] = row.slots[replaySlots[i]];
		}
		materialized.add(values);
		session.materializedRow();
	}

	void releaseReplay() {
		if (replayMark >= 0) {
			row.rollback(replayMark);
			replayMark = -1;
		}
	}

	@Override
	public void close() {
		releaseReplay();
		closeRight();
		if (rightProbe != null) {
			rightProbe.close();
			rightProbe = null;
		}
		leftCursor.close();
	}

	void closeRight() {
		if (rightCursor != null) {
			rightCursor.close();
			rightCursor = null;
		}
	}
}

@Experimental
final class AdaptiveOwningCursor implements RowCursor {
	final RowCursor arg;
	final AdaptiveFilterSession session;
	final NativeFilterLease lease;
	boolean closed;

	AdaptiveOwningCursor(RowCursor arg, AdaptiveFilterSession session, NativeFilterLease lease) {
		this.arg = arg;
		this.session = session;
		this.lease = lease;
	}

	@Override
	public boolean next() throws IOException {
		try {
			return arg.next();
		} catch (IOException | RuntimeException | Error failure) {
			closeAfterFailure(failure);
			throw failure;
		}
	}

	@Override
	public void close() {
		if (closed) {
			return;
		}
		closed = true;
		Throwable failure = null;
		try {
			arg.close();
		} catch (RuntimeException | Error problem) {
			failure = problem;
		}
		try {
			session.close();
		} catch (RuntimeException | Error problem) {
			failure = addFailure(failure, problem);
		}
		if (failure == null) {
			lease.commit();
			session.publishTelemetry();
			return;
		}
		lease.abort(failure);
		rethrow(failure);
	}

	private void closeAfterFailure(Throwable primary) {
		if (closed) {
			return;
		}
		closed = true;
		try {
			arg.close();
		} catch (RuntimeException | Error problem) {
			addFailure(primary, problem);
		}
		try {
			session.close();
		} catch (RuntimeException | Error problem) {
			addFailure(primary, problem);
		}
		lease.abort(primary);
	}

	private static Throwable addFailure(Throwable primary, Throwable later) {
		if (primary == null) {
			return later;
		}
		if (primary != later) {
			primary.addSuppressed(later);
		}
		return primary;
	}

	private static void rethrow(Throwable failure) {
		if (failure instanceof RuntimeException runtimeException) {
			throw runtimeException;
		}
		throw (Error) failure;
	}
}
